import{_ as o,o as a,c as r,a0 as t}from"./chunks/framework.BjpW4enL.js";const m=JSON.parse('{"title":"Glossário NEXUS","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"Z_Archive/wiki_legacy/reference/glossary.md","filePath":"Z_Archive/wiki_legacy/reference/glossary.md","lastUpdated":1782593311000}'),s={name:"Z_Archive/wiki_legacy/reference/glossary.md"};function n(d,e,i,c,u,p){return a(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="glossario-nexus" tabindex="-1">Glossário NEXUS <a class="header-anchor" href="#glossario-nexus" aria-label="Permalink to &quot;Glossário NEXUS&quot;">​</a></h1><blockquote><p>40+ termos essenciais para navegar o sistema.</p></blockquote><hr><h2 id="a" tabindex="-1">A <a class="header-anchor" href="#a" aria-label="Permalink to &quot;A&quot;">​</a></h2><p><strong>Abstraction</strong> : Unidade de conhecimento em um nível específico (L0-L4). Armazenada na tabela <code>abstractions</code> do PostgreSQL. Cada abstraction tem um <code>blob_id</code> (arquivo de origem), <code>level</code> (nível de abstração), <code>chunk_index</code> (posição no blob) e <code>content</code> (conteúdo textual).</p><p><strong>ADR (Architecture Decision Record)</strong> : Documento que registra uma decisão arquitetural significativa, incluindo contexto, opções consideradas, decisão tomada e consequências. Os ADRs do NEXUS estão em <code>docs/adr/</code>.</p><p><strong>Agent (Agente de IA)</strong> : Consumidor primário do NEXUS. Um LLM que navega no grafo via MCP tools para entender uma base de código.</p><p><strong>Agent Links</strong> : Tabela no PostgreSQL (<code>agent_links</code>) que armazena as arestas do grafo multi-relacional T4. Contém <code>source_id</code>, <code>target_id</code>, <code>criteria</code> (tipo da aresta), <code>weight</code> e <code>created_at</code>.</p><p><strong>ast-grep</strong> : Ferramenta de análise sintática estática usada para extrair estruturas de código (funções, classes, interfaces) de arquivos fonte. É o motor do L1.</p><hr><h2 id="b" tabindex="-1">B <a class="header-anchor" href="#b" aria-label="Permalink to &quot;B&quot;">​</a></h2><p><strong>Blob</strong> : Arquivo fonte completo ingerido pelo sistema. Armazenado na tabela <code>blobs</code> com <code>fs_path</code>, <code>source_hash</code>, <code>raw_content</code> e <code>metadata</code>. Um blob é dividido em múltiplas abstractions (chunks).</p><hr><h2 id="c" tabindex="-1">C <a class="header-anchor" href="#c" aria-label="Permalink to &quot;C&quot;">​</a></h2><p><strong>Chunk</strong> : Fragmento de um blob em um nível de abstração. Um chunk L0 é um trecho de código fonte; um chunk L1 é uma estrutura AST extraída; um chunk L2 é uma descrição semântica gerada por LLM.</p><p><strong>Context Pack</strong> : Grupo de abstrações que formam uma janela de contexto coerente para o agente. Inclui uma abstração central + chunks vizinhos do mesmo blob. Materializado pelo <code>build_context_packs()</code> em <code>query.rs</code>.</p><p><strong>Context Event</strong> : Entrada de observabilidade no pipeline. Registra toda operação que consome tokens (prompts, respostas, embeddings) para auditoria e garbage collection. Tabela <code>context_events</code>.</p><p><strong>Contradicts</strong> : Tipo de aresta T4 que conecta abstrações semanticamente conflitantes. Ex: duas versões da mesma função com comportamentos diferentes.</p><hr><h2 id="d" tabindex="-1">D <a class="header-anchor" href="#d" aria-label="Permalink to &quot;D&quot;">​</a></h2><p><strong>Decaimento (Decay)</strong> : Mecanismo proposto (ADR-0021) para reduzir gradualmente o peso de arestas obsoletas no grafo T4, permitindo que conexões irrelevantes &quot;esfriem&quot; e desapareçam.</p><p><strong>Dependências (depends_on:imports)</strong> : Tipo de aresta T4 que conecta um arquivo a outro que ele importa. Representa o esqueleto estrutural do código.</p><p><strong>Deriva Semântica (Semantic Drift)</strong> : Perda de precisão semântica ao longo do tempo ou entre saltos de contexto. O NEXUS mitiga isso combinando T3 (busca aproximada) com T4 (navegação exata).</p><hr><h2 id="e" tabindex="-1">E <a class="header-anchor" href="#e" aria-label="Permalink to &quot;E&quot;">​</a></h2><p><strong>Embedding</strong> : Vetor numérico (768d no NEXUS) que representa o significado semântico de um texto. Gerado por <code>nomic-embed-text</code>.</p><p><strong>Enrichment Pipeline</strong> : Pipeline que transforma código bruto (L0) em abstrações estruturadas (L1), semânticas (L2) e links topológicos (T4). Executado por <code>run_enrichment()</code> em loop contínuo.</p><hr><h2 id="f" tabindex="-1">F <a class="header-anchor" href="#f" aria-label="Permalink to &quot;F&quot;">​</a></h2><p><strong>File Node</strong> : Nó no grafo T4 que representa um arquivo completo (L4). Todos os chunks L0/L1/L2 de um arquivo se conectam ao seu file node via <code>part_of</code>. É o ponto de entrada estrutural para navegação.</p><p><strong>Filesystem Watch</strong> : Mecanismo que monitora mudanças no sistema de arquivos (create, modify, delete) e dispara re-ingestão automática. Implementado via <code>notify</code> crate.</p><hr><h2 id="g" tabindex="-1">G <a class="header-anchor" href="#g" aria-label="Permalink to &quot;G&quot;">​</a></h2><p><strong>Grafo Multi-Relacional (T4)</strong> : Estrutura de dados que conecta abstrações através de 4 tipos de aresta (<code>part_of</code>, <code>depends_on:imports</code>, <code>semantic_bridge</code>, <code>contradicts</code>) com 3 eixos de projeção (<code>criteria</code>, <code>file_type</code>, <code>project</code>).</p><p><strong>GPS (metáfora T3)</strong> : A camada de busca vetorial (Qdrant) que entende intenção e proximidade semântica. &quot;Onde fica a lógica de agendamento?&quot;</p><hr><h2 id="h" tabindex="-1">H <a class="header-anchor" href="#h" aria-label="Permalink to &quot;H&quot;">​</a></h2><p><strong>Heat (Calor)</strong> : Métrica de atividade/importância no grafo T4. Abstrações acessadas frequentemente recebem mais heat; o heat decai com o tempo. Implementação proposta no ADR-0024.</p><hr><h2 id="i" tabindex="-1">I <a class="header-anchor" href="#i" aria-label="Permalink to &quot;I&quot;">​</a></h2><p><strong>Ingest Queue</strong> : Máquina de estados para controle de ingestão de arquivos. Estados: <code>pending</code> → <code>processing</code> → <code>completed</code> | <code>failed</code>. Tabela <code>ingest_queue</code>.</p><hr><h2 id="l" tabindex="-1">L <a class="header-anchor" href="#l" aria-label="Permalink to &quot;L&quot;">​</a></h2><p><strong>L0 (Nível 0)</strong> : Chunk bruto de código fonte. O nível mais baixo de abstração.</p><p><strong>L1 (Nível 1)</strong> : Abstração estrutural. Extraída deterministicamente via <code>ast-grep</code> do arquivo completo. Contém funções, classes, interfaces, structs — o que o código <strong>é</strong>.</p><p><strong>L2 (Nível 2)</strong> : Abstração semântica. Gerada por LLM (Ollama) usando contexto L1 + RAG. Contém descrições em linguagem natural do propósito do código — o que o código <strong>faz</strong>.</p><p><strong>L3 (Nível 3)</strong> : Síntese arquitetural. Emerge da detecção de comunidades no grafo T4, não de um blob individual. Descreve o propósito arquitetural de um módulo inteiro.</p><p><strong>L4 (Nível 4)</strong> : File node. Representa um arquivo completo no grafo T4. Não é uma abstração do conteúdo, mas um nó estrutural para navegação.</p><hr><h2 id="m" tabindex="-1">M <a class="header-anchor" href="#m" aria-label="Permalink to &quot;M&quot;">​</a></h2><p><strong>Mapa da Cidade (metáfora T4)</strong> : A camada de grafo (PostgreSQL) que representa a estrutura exata do código: CEP (caminho do arquivo), hierarquia (quem contém quem), imports (quem depende de quem).</p><p><strong>MCP (Model Context Protocol)</strong> : Protocolo padronizado para comunicação entre LLMs e ferramentas. O NEXUS expõe suas capacidades como tools MCP via servidor SSE em <code>localhost:7474</code>.</p><p><strong>Module</strong> : Agrupamento semântico de arquivos dentro de um projeto. Classificado por regras em <code>nexus_config.json</code> (<code>module_rules</code>).</p><hr><h2 id="n" tabindex="-1">N <a class="header-anchor" href="#n" aria-label="Permalink to &quot;N&quot;">​</a></h2><p><strong>nexus_adjacent()</strong> : Tool MCP que caminha no grafo T4. Dado um node_id, retorna os vizinhos com suas arestas. A navegação pode ser filtrada por criteria (tipo de aresta).</p><p><strong>nexus_admin()</strong> : Tool MCP para administração do sistema. Ações: <code>enrich</code> (força pipeline), <code>ingest</code> (clona repositório), <code>status</code> (progresso de ingestão).</p><p><strong>nexus_guide()</strong> : Tool MCP que retorna o protocolo operacional completo do NEXUS. <strong>Deve ser chamada primeiro</strong> por qualquer agente ao iniciar trabalho.</p><p><strong>nexus_link()</strong> : Tool MCP que cristaliza uma descoberta do agente como uma nova aresta no grafo T4 (memória stigmergic). Permite que um agente deixe trilhas para agentes futuros.</p><p><strong>nexus_map()</strong> : Tool MCP que retorna o mapa estrutural de um projeto ou módulo: lista de arquivos, módulos e métricas de deriva arquitetural.</p><p><strong>nexus_query()</strong> : Tool MCP principal para busca. Combina T3 (busca semântica) com triangulação L1 (estrutura) e retorna Context Packs. Parâmetros: <code>query</code>, <code>extensions</code>, <code>collection</code>, <code>triangulate</code>, <code>top_k</code>, <code>max_chunks_per_file</code>, <code>context_radius</code>.</p><p><strong>nexus_reflections()</strong> : Tool MCP que retorna insights arquiteturais de alto nível (L3) gerados pelo sistema.</p><p><strong>nomic-embed-text</strong> : Modelo de embeddings da Ollama usado pelo NEXUS. Gera vetores 768d para busca semântica. Executa em CPU. Latência ~85ms.</p><hr><h2 id="p" tabindex="-1">P <a class="header-anchor" href="#p" aria-label="Permalink to &quot;P&quot;">​</a></h2><p><strong>PPR (Personalized PageRank)</strong> : Algoritmo de walk no grafo T4 usado para expandir contexto a partir de seeds semânticas. Propaga scores pelas arestas, gerando um subgrafo rankeado.</p><p><strong>Pipeline Metrics</strong> : Métricas temporais coletadas a cada chamada ao Ollama: TTFT, TPOT, throughput, prompt eval count. Tabela <code>pipeline_metrics</code>.</p><p><strong>Projection</strong> : Fatia do grafo T4 definida pela interseção de 3 eixos: <code>criteria</code> × <code>file_type</code> × <code>project</code>. Toda navegação é uma projeção.</p><hr><h2 id="q" tabindex="-1">Q <a class="header-anchor" href="#q" aria-label="Permalink to &quot;Q&quot;">​</a></h2><p><strong>qwen2.5-coder:nexus</strong> : Modelo de linguagem local usado para geração de descrições semânticas L2 e síntese L3. 1.5B parâmetros, 29 layers offloaded na GPU. ~4.5GB VRAM.</p><hr><h2 id="s" tabindex="-1">S <a class="header-anchor" href="#s" aria-label="Permalink to &quot;S&quot;">​</a></h2><p><strong>Semaphore</strong> : Mecanismo de controle de concorrência. O NEXUS usa um semáforo global de 2 permits para chamadas ao Ollama, prevenindo OOM na GPU.</p><p><strong>semantic_bridge</strong> : Tipo de aresta T4 que conecta arquivos semanticamente similares. Representa a &quot;carne&quot; do grafo — conexões que emergem de similaridade de propósito.</p><p><strong>Stigmergy</strong> : Comunicação indireta entre agentes através do ambiente. No NEXUS, agentes registram descobertas via <code>nexus_link()</code>, criando arestas que agentes futuros podem navegar.</p><p><strong>Superseded By</strong> : Mecanismo de encadeamento temporal (T6). Uma abstração pode ser &quot;substituída por&quot; outra quando o arquivo fonte é re-ingerido, formando uma cadeia de versões.</p><hr><h2 id="t" tabindex="-1">T <a class="header-anchor" href="#t" aria-label="Permalink to &quot;T&quot;">​</a></h2><p><strong>T1</strong> : Camada de Filesystem. Fonte da verdade original.</p><p><strong>T2</strong> : Camada de PostgreSQL. Âncora canônica de dados estruturados.</p><p><strong>T3</strong> : Camada de Qdrant. Busca vetorial por proximidade semântica.</p><p><strong>T4</strong> : Camada de Grafo Multi-Relacional. Navegação topológica com arestas tipadas.</p><p><strong>T5</strong> : Camada de Reflections. Insights arquiteturais emergentes (L3).</p><p><strong>T6</strong> : Camada de Time. Encadeamento temporal de versões.</p><p><strong>Tokio</strong> : Runtime assíncrono Rust usado pelo coordinator. Gerencia os loops de enrichment, file watcher, query server e MCP server concorrentemente.</p><p><strong>Triangulação</strong> : Cruzamento de resultado semântico (L2) com estrutura (L1) para validação. Quando <code>triangulate=true</code> em <code>nexus_query()</code>, cada resultado L2 é verificado contra sua contraparte L1.</p><hr><h2 id="w" tabindex="-1">W <a class="header-anchor" href="#w" aria-label="Permalink to &quot;W&quot;">​</a></h2><p><strong>Weaver</strong> : Componente do pipeline que cria arestas T4. Chama <code>process_batch()</code> no final de cada ciclo L2 para gerar links <code>part_of</code>, <code>depends_on:imports</code>, <code>semantic_bridge</code> e <code>contradicts</code>.</p>',90)])])}const g=o(s,[["render",n]]);export{m as __pageData,g as default};
